solution: ```class Solution {
    public int[] separateDigits(int[] nums) {
        int totalDigits = 0;
        for (int num : nums) {
            totalDigits += (num == 0) ? 1 : (int) Math.log10(num) + 1;
        }
        int[] answer = new int[totalDigits];
        int idx = 0;
        for (int num : nums) {
            String s = Integer.toString(num);
            for (char c : s.toCharArray()) {
                answer[idx++] = c - '0';
            }
        }
        return answer;
    }
}
